package com.interview.incidentrca.config;import io.swagger.v3.oas.models.*;import io.swagger.v3.oas.models.info.Info;import io.swagger.v3.oas.models.security.*;import org.springframework.context.annotation.*;
@Configuration public class OpenApiConfig{@Bean OpenAPI api(){return new OpenAPI().info(new Info().title("AI-Assisted Incident Management & RCA API").version("1.0").description("Enterprise incident lifecycle, RCA suggestions, SLA tracking and analytics API.")).addSecurityItem(new SecurityRequirement().addList("bearerAuth")).components(new Components().addSecuritySchemes("bearerAuth",new SecurityScheme().type(SecurityScheme.Type.HTTP).scheme("bearer").bearerFormat("JWT")));}}
